import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Account, INDUSTRIES } from '../../models/models';

@Component({
  selector: 'app-account-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './account-list.component.html',
  styleUrl: './accounts.css',
})
export class AccountListComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly industries = INDUSTRIES;

  private params = toSignal(this.route.queryParamMap, { initialValue: this.route.snapshot.queryParamMap });
  readonly search = computed(() => this.params().get('q') ?? '');
  readonly industry = computed(() => this.params().get('industry') ?? '');

  accounts = signal<Account[]>([
    { id: 'a1', name: 'Acme Corporation', industry: 'Manufacturing', website: 'acme.com', phone: '+1 415 555 0100', city: 'San Francisco', employees: 4200, annualRevenue: 320000000, owner: 'Demo Admin' },
    { id: 'a2', name: 'Globex Industries', industry: 'Technology', website: 'globex.io', phone: '+1 212 555 0142', city: 'New York', employees: 1800, annualRevenue: 145000000, owner: 'Priya Nair' },
    { id: 'a3', name: 'Initech', industry: 'Finance', website: 'initech.com', phone: '+1 512 555 0188', city: 'Austin', employees: 640, annualRevenue: 58000000, owner: 'Marco Diaz' },
    { id: 'a4', name: 'Umbrella Health', industry: 'Healthcare', website: 'umbrella-health.org', phone: '+1 617 555 0164', city: 'Boston', employees: 9500, annualRevenue: 1200000000, owner: 'Demo Admin' },
    { id: 'a5', name: 'Soylent Foods', industry: 'Retail', website: 'soylentfoods.com', phone: '+1 312 555 0171', city: 'Chicago', employees: 2300, annualRevenue: 210000000, owner: 'Priya Nair' },
    { id: 'a6', name: 'Stark Energy', industry: 'Energy', website: 'starkenergy.com', phone: '+1 213 555 0133', city: 'Los Angeles', employees: 7600, annualRevenue: 890000000, owner: 'Marco Diaz' },
    { id: 'a7', name: 'Wayne Media', industry: 'Media', website: 'waynemedia.tv', phone: '+1 646 555 0119', city: 'New York', employees: 1200, annualRevenue: 96000000, owner: 'Demo Admin' },
    { id: 'a8', name: 'Hooli Cloud', industry: 'Technology', website: 'hooli.com', phone: '+1 408 555 0155', city: 'Palo Alto', employees: 5400, annualRevenue: 540000000, owner: 'Priya Nair' },
    { id: 'a9', name: 'Vandelay Imports', industry: 'Retail', website: 'vandelay.co', phone: '+1 305 555 0177', city: 'Miami', employees: 320, annualRevenue: 24000000, owner: 'Marco Diaz' },
    { id: 'a10', name: 'Pied Piper', industry: 'Technology', website: 'piedpiper.com', phone: '+1 650 555 0102', city: 'Palo Alto', employees: 140, annualRevenue: 12000000, owner: 'Demo Admin' },
  ]);

  readonly filtered = computed(() => {
    const q = this.search().toLowerCase().trim();
    const ind = this.industry();
    return this.accounts().filter((a) => {
      const matchesQ = !q || a.name.toLowerCase().includes(q) || a.city.toLowerCase().includes(q);
      const matchesInd = !ind || a.industry === ind;
      return matchesQ && matchesInd;
    });
  });

  onSearch(value: string): void {
    this.router.navigate([], { queryParams: { q: value || null }, queryParamsHandling: 'merge' });
  }
  onIndustry(value: string): void {
    this.router.navigate([], { queryParams: { industry: value || null }, queryParamsHandling: 'merge' });
  }
}
